if (NomenclatureMgr.getFlagShowNomenclature()) {
    core.debug("Planetary surface feature names are visible");
}

if (NomenclatureMgr.getFlagShowTerminatorZoneOnly()) {
    core.debug("Only terminator zone nomenclature is visible");
}

// Show only features near terminator
NomenclatureMgr.setFlagShowTerminatorZoneOnly(true);

// Show all features
NomenclatureMgr.setFlagShowTerminatorZoneOnly(false);

// Show features with solar altitude between -5° and 40°
NomenclatureMgr.setTerminatorMinAltitude(-5);
NomenclatureMgr.setTerminatorMaxAltitude(40);
NomenclatureMgr.setFlagShowTerminatorZoneOnly(true);

if (NomenclatureMgr.getFlagOutlineCraters()) {
    core.debug("Crater outlines are drawn");
}

// Draw elliptical outlines around craters
NomenclatureMgr.setFlagOutlineCraters(true);

// Hide crater outlines
NomenclatureMgr.setFlagOutlineCraters(false);

if (NomenclatureMgr.getFlagHideLocalNomenclature()) {
    core.debug("Labels on the current planet are hidden");
}

// Hide Earth features when on Earth
NomenclatureMgr.setFlagHideLocalNomenclature(true);

// Show Earth features even when on Earth
NomenclatureMgr.setFlagHideLocalNomenclature(false);

if (NomenclatureMgr.getFlagShowSpecialNomenclatureOnly()) {
    core.debug("Only poles and special points are shown");
}

// Show only poles and special points
NomenclatureMgr.setFlagShowSpecialNomenclatureOnly(true);

// Show all surface features
NomenclatureMgr.setFlagShowSpecialNomenclatureOnly(false);

// Recommended way to read color
var colorStr = core.getStelProperty('NomenclatureMgr.nomenclatureColor');
var parts = colorStr.split(',');

// Alternative: use getColor() but result cannot be indexed directly
var color = NomenclatureMgr.getColor();
core.debug("Color object type: " + typeof color);

// Set nomenclature labels to light green
var lightGreen = core.vec3f(0.2, 0.8, 0.2);
NomenclatureMgr.setColor(lightGreen);

// Set to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
NomenclatureMgr.setColor(cyan);

// Read color using property
var colorStr = core.getStelProperty('NomenclatureMgr.nomenclatureColor');
var parts = colorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);
core.debug("Color: RGB(" + r + ", " + g + ", " + b + ")");

// Write using setColor method
var newColor = core.vec3f(0.2, 0.8, 0.2);
NomenclatureMgr.setColor(newColor);

// Force translation update after manual language change
NomenclatureMgr.updateI18n();
core.debug("Nomenclature translations updated");

var t = NomenclatureMgr.searchByEnglishName("Tycho");
if (t) {
    core.debug("Found Tycho crater on the Moon");
    core.moveToObject(t.getEnglishName(), 2);
}
